const { default: axios } = require('axios');
const { default: FormData } = require('form-data');
const { default: fs } = require('fs');
const { default: path } = require('path');
const { default: child_process } = require('child_process');

exports.handler = async function(context) {
  const inputFilename = context.req.body.inputFilename;
  const outputFormat = context.req.body.outputFormat;

  if (!inputFilename || !outputFormat) {
    return { statusCode: 400, body: 'Invalid request' };
  }

  const filePath = path.join(__dirname, inputFilename);
  const outputPath = path.join(__dirname, `output-${Date.now()}.${outputFormat}`);

  try {
    await fs.promises.access(filePath);
  } catch (err) {
    return { statusCode: 404, body: 'File not found' };
  }

  const formData = new FormData();
  formData.append('input', fs.createReadStream(filePath));
  formData.append('output', fs.createWriteStream(outputPath));

  const args = [
    '-env:UserInstallation=file:///usr/share/libreoffice/4',
    `-env:DOSYSTEM_TYPE=unix`,
    '--headless',
    `--convert-to ${outputFormat}`,
    `--outdir ${path.dirname(outputPath)}`,
  ];

  try {
    const process = child_process.spawnSync('libreoffice', args, { input: formData });
    if (process.error) {
      return { statusCode: 500, body: 'Internal server error' };
    } else {
      return { statusCode: 200, body: 'Document converted successfully' };
    }
  } catch (err) {
    return { statusCode: 500, body: 'Internal server error' };
  }
};